# === Tree Data Structures ===

# Binary Tree Node
class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

# BST Search (iterative)
def bst_search(root, target):
    while root:
        if target == root.val: return root
        root = root.left if target < root.val else root.right
    return None

# Heap (Min-Heap)
import heapq
heap = [3, 1, 4, 1, 5]
heapq.heapify(heap)          # O(n)
smallest = heapq.heappop(heap)  # O(log n)

# Trie
class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end = False

class Trie:
    def __init__(self):
        self.root = TrieNode()
    def insert(self, word):
        node = self.root
        for ch in word:
            if ch not in node.children:
                node.children[ch] = TrieNode()
            node = node.children[ch]
        node.is_end = True

# === Graph Data Structures ===

# Adjacency List using defaultdict
from collections import defaultdict, deque

graph = defaultdict(list)
graph[0].extend([1, 2])
graph[1].append(0)
graph[2].extend([0, 3])
graph[3].append(2)

# DFS (iterative)
def dfs(graph, start):
    visited = set()
    stack = [start]
    while stack:
        node = stack.pop()
        if node in visited: continue
        visited.add(node)
        for nb in graph[node]:
            if nb not in visited:
                stack.append(nb)
    return visited

# BFS
def bfs(graph, start):
    visited = {start}
    queue = deque([start])
    while queue:
        node = queue.popleft()
        for nb in graph[node]:
            if nb not in visited:
                visited.add(nb)
                queue.append(nb)
    return visited

print(bfs(graph, 0))  # {0, 1, 2, 3}
